-- wrap the HBI CTE (see health-burden-index-worst-districts) as hbi(district_name,state_ut,health_burden_index), then:
SELECT trim(state_ut) AS state, count(*) AS n_districts, round(avg(health_burden_index),1) AS mean_hbi
FROM hbi GROUP BY trim(state_ut) HAVING count(*) >= 3 ORDER BY mean_hbi DESC;

SELECT min(v) min_, percentile(v,0.1) p10, percentile(v,0.5) median, percentile(v,0.9) p90, max(v) max_
FROM (SELECT try_cast(regexp_replace(all_w15_49_who_are_anaemic_pct,'[()*]','') AS DOUBLE) AS v
      FROM databricks_virtue_foundation_dataset_dais_2026.virtue_foundation_dataset.nfhs_5_district_health_indicators) WHERE v IS NOT NULL;

